/**
 * Generate Whale Alert firewall config.
 *
 * Data source: https://developer.whale-alert.io/documentation/
 *
 * Whale Alert REST APIs authenticate with an API key passed as the api_key
 * query parameter.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://developer.whale-alert.io/documentation/";
const PLACEHOLDER_VALUE = "Coffee5afe10ca1Coffee5afe10ca1Co";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Whale Alert API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:whale-alert",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const whaleAlertFirewall = {",
    '  name: "whale-alert",',
    '  description: "Whale Alert API",',
    "  placeholders: {",
    `    WHALE_ALERT_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://leviathan.whale-alert.io",',
    "      auth: {",
    "        query: {",
    '          api_key: "${{ secrets.WHALE_ALERT_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://api.whale-alert.io/v1",',
    "      auth: {",
    "        query: {",
    '          api_key: "${{ secrets.WHALE_ALERT_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Whale Alert firewall config...");
  const ts = generateTypeScript();
  writeOutput("whale-alert", ts, import.meta.dirname);
}
